package codegen

import (
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// genConfigGo writes a minimal go.mod (GenerateConfigLoader needs the module
// path for the gen/config/v1 import the thin shim emits) and returns the
// rendered pkg/config/config.go. The config object IS the proto type now, so
// the generated file is a THIN ALIAS shim — there is no parallel Config
// struct and no per-field loader to assert.
func genConfigGo(t *testing.T, messages []ConfigMessage) string {
	t.Helper()
	dir := t.TempDir()
	if err := os.WriteFile(filepath.Join(dir, "go.mod"), []byte("module example.com/proj\n\ngo 1.24\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	if err := GenerateConfigLoader(messages, dir, nil); err != nil {
		t.Fatalf("GenerateConfigLoader() error = %v", err)
	}
	data, err := os.ReadFile(filepath.Join(dir, "pkg", "config", "config.go"))
	if err != nil {
		t.Fatalf("ReadFile() error = %v", err)
	}
	// The generated shim must always be valid Go.
	fset := token.NewFileSet()
	if _, perr := parser.ParseFile(fset, "config.go", data, parser.AllErrors); perr != nil {
		t.Fatalf("generated config.go does not parse: %v\n%s", perr, data)
	}
	return string(data)
}

func basicMessages() []ConfigMessage {
	return []ConfigMessage{{
		Name: "AppConfig",
		Fields: []ConfigField{
			{Name: "port", GoName: "Port", GoType: "int32", ProtoType: "int32", EnvVar: "PORT", Flag: "port", DefaultValue: "8080", Description: "HTTP server port"},
			{Name: "log_level", GoName: "LogLevel", GoType: "string", ProtoType: "string", EnvVar: "LOG_LEVEL", Flag: "log-level", DefaultValue: "info", Description: "Log level"},
			{Name: "database_url", GoName: "DatabaseUrl", GoType: "string", ProtoType: "string", EnvVar: "DATABASE_URL", Flag: "database-url", Required: true, Description: "PostgreSQL connection string"},
		},
	}}
}

// TestGenerateConfigLoader_ThinAliasShim pins the cutover invariant: the
// generated pkg/config/config.go is a THIN shim over forge/pkg/config and the
// gen proto type — NOT a parallel struct + per-field loader.
func TestGenerateConfigLoader_ThinAliasShim(t *testing.T) {
	content := genConfigGo(t, basicMessages())

	for _, want := range []string{
		"Code generated by forge. DO NOT EDIT.",
		// Config IS the proto type via a type alias.
		"type Config = configv1.AppConfig",
		// Imports the project's generated proto config package and the lib.
		`configv1 "example.com/proj/gen/config/v1"`,
		`forgeconfig "github.com/reliant-labs/forge/pkg/config"`,
		// RegisterFlags / Load delegate to the descriptor-driven library.
		"func RegisterFlags(cmd *cobra.Command)",
		"forgeconfig.RegisterFlags(cmd, &configv1.AppConfig{})",
		"func Load(cmd *cobra.Command) (*Config, error)",
		"forgeconfig.LoadTyped[*configv1.AppConfig](cmd)",
		// Free funcs over the message — never methods on a generated struct.
		"func Validate(cfg *Config) error",
		"func DevAuthBypass(cfg *Config) bool",
		"forgeconfig.Validate(cfg)",
		"forgeconfig.DevAuthBypass(cfg)",
	} {
		if !strings.Contains(content, want) {
			t.Errorf("generated config.go missing %q\n%s", want, content)
		}
	}
}

// TestGenerateConfigLoader_NoParallelStruct is the load-bearing negative: the
// deleted generated struct + per-field loader must NOT come back. No `type
// Config struct`, no per-field `loadField` plumbing, no per-field flag
// registration, no `func (c *Config) ...` methods.
func TestGenerateConfigLoader_NoParallelStruct(t *testing.T) {
	content := genConfigGo(t, DefaultConfigMessages())

	for _, banned := range []string{
		"type Config struct",
		"func loadField[",
		"loadField(cmd,",
		"cmd.Flags().Int32(",
		"cmd.Flags().String(",
		"cmd.Flags().Bool(",
		"func (c *Config)",
		"func parseGoDuration",
		"time.Duration", // no typed-duration struct fields anymore
	} {
		if strings.Contains(content, banned) {
			t.Errorf("generated config.go must NOT contain deleted-shape token %q\n%s", banned, content)
		}
	}
}

func TestGenerateConfigLoader_EmptyMessages(t *testing.T) {
	targetDir := t.TempDir()
	if err := GenerateConfigLoader(nil, targetDir, nil); err != nil {
		t.Fatalf("GenerateConfigLoader() error = %v", err)
	}
	if _, err := os.Stat(filepath.Join(targetDir, "pkg", "config", "config.go")); !os.IsNotExist(err) {
		t.Error("GenerateConfigLoader with empty messages should not create config.go")
	}
}
